// 1. Primitiv dəyişənlər
public class PrimitiveVariables {
  public static void main(String[] args) {
    int age = 25; // Tam ədəd
    double price = 99.99; // Onluq ədəd
    boolean isStudent = true; // Boolean
    char grade = 'A'; // Simvol
    System.out.println("Age: " + age + ", Price: " + price + ", Student: " + isStudent + ", Grade: " + grade);
  }
}
// Çıxış: Age: 25, Price: 99.99, Student: true, Grade: A

// 2. Qeyri-primitiv dəyişənlər
public class NonPrimitiveVariables {
  public static void main(String[] args) {
    String name = "Alice"; // Sətir
    int[] numbers = {1, 2, 3}; // Massiv
    System.out.println("Name: " + name);
    System.out.print("Numbers: ");
    for (int num : numbers) {
      System.out.print(num + " ");
    }
  }
}
// Çıxış: Name: Alice
// Numbers: 1 2 3

// 3. Sabitlər (final)
public class ConstantsExample {
  public static void main(String[] args) {
    final double PI = 3.14159; // Sabit
    // PI = 3.14; // Səhv: Sabit dəyişdirilə bilməz
    System.out.println("PI: " + PI);
  }
}
// Çıxış: PI: 3.14159

// 4. Lokal, nümunə və statik dəyişənlər
public class ScopeExample {
  static int staticCounter = 0; // Statik dəyişən
  int instanceCounter = 0; // Nümunə dəyişəni

  public void increment() {
    int localCounter = 0; // Lokal dəyişən
    localCounter++;
    instanceCounter++;
    staticCounter++;
    System.out.println("Local: " + localCounter + ", Instance: " + instanceCounter + ", Static: " + staticCounter);
  }

  public static void main(String[] args) {
    ScopeExample obj1 = new ScopeExample();
    ScopeExample obj2 = new ScopeExample();
    obj1.increment();
    obj2.increment();
  }
}
// Çıxış: Local: 1, Instance: 1, Static: 1
// Local: 1, Instance: 1, Static: 2

// 5. Tip çevirməsi (Type Casting)
public class TypeCastingExample {
  public static void main(String[] args) {
    int intValue = 100;
    double doubleValue = intValue; // Avtomatik çevirmə (widening)
    System.out.println("Double: " + doubleValue);

    double anotherDouble = 99.99;
    int anotherInt = (int) anotherDouble; // Açıq çevirmə (narrowing)
    System.out.println("Int: " + anotherInt);
  }
}
// Çıxış: Double: 100.0
// Int: 99

public class Product {
  String id;
  String name;
  double price;
  boolean inStock;

  public Product(String id, String name, double price, boolean inStock) {
    this.id = id;
    this.name = name;
    this.price = price;
    this.inStock = inStock;
  }

  public String getInfo() {
    return "Product: " + name + ", ID: " + id + ", Price: " + price + ", In Stock: " + inStock;
  }

  public static void main(String[] args) {
    Product product1 = new Product("P001", "Laptop", 999.99, true);
    Product product2 = new Product("P002", "Phone", 499.99, false);
    System.out.println(product1.getInfo());
    System.out.println(product2.getInfo());
  }
}
// Çıxış: Product: Laptop, ID: P001, Price: 999.99, In Stock: true
// Product: Phone, ID: P002, Price: 499.99, In Stock: false

