// 4. Local, Instance, and Static Variables
public class ScopeExample {
  static int staticCounter = 0; // Static variable
  int instanceCounter = 0; // Instance variable

  public void increment() {
    int localCounter = 0; // Local variable
    localCounter++;
    instanceCounter++;
    staticCounter++;
    System.out.println("Local: " + localCounter + ", Instance: " + instanceCounter + ", Static: " + staticCounter);
  }

  public static void main(String[] args) {
    ScopeExample obj1 = new ScopeExample();
    ScopeExample obj2 = new ScopeExample();
    obj1.increment();
    obj2.increment();
  }
}
// Output: Local: 1, Instance: 1, Static: 1
// Local: 1, Instance: 1, Static: 2

